import{_ as i,c as t,o as a,ag as s}from"./chunks/framework.BONmpqY0.js";const h=JSON.parse('{"title":"Cross-Source Deduplication System","description":"","frontmatter":{},"headers":[],"relativePath":"deduplication/index.md","filePath":"deduplication/index.md"}'),r={name:"deduplication/index.md"};function o(n,e,l,c,d,u){return a(),t("div",null,e[0]||(e[0]=[s('<h1 id="cross-source-deduplication-system" tabindex="-1">Cross-Source Deduplication System <a class="header-anchor" href="#cross-source-deduplication-system" aria-label="Permalink to &quot;Cross-Source Deduplication System&quot;">​</a></h1><p>The MARA cross-source deduplication system identifies and merges duplicate maritime incident reports from different maritime reporting sources (RECAAP, UKMTO, MDAT, ICC). This system enhances data quality by combining complementary information from multiple sources into a single, comprehensive incident record.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Maritime incidents are often reported by multiple organizations, with each source providing slightly different details about the same event. The deduplication system:</p><ol><li>Identifies likely matches across different reporting sources</li><li>Determines which record is more complete/authoritative</li><li>Merges complementary information</li><li>Maintains relationships between merged records</li></ol><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Multi-dimensional matching</strong>: Uses time, location, vessel details, and incident type for similarity scoring</li><li><strong>Source-aware processing</strong>: Accounts for differences in data completeness across reporting sources</li><li><strong>Configurable confidence thresholds</strong>: Adjustable scoring system to control merge aggressiveness</li><li><strong>Complementary data merging</strong>: Intelligently combines information from multiple sources</li><li><strong>Source attribution preservation</strong>: Maintains references to original sources</li><li><strong>Background processing</strong>: Runs automatically as scheduled Netlify functions</li></ul><h2 id="system-architecture" tabindex="-1">System Architecture <a class="header-anchor" href="#system-architecture" aria-label="Permalink to &quot;System Architecture&quot;">​</a></h2><p>The deduplication system consists of:</p><ol><li><strong>Background Function</strong>: <code>deduplicate-cross-source-background.js</code> scheduled in Netlify</li><li><strong>Utility Modules</strong>: <ul><li><code>spatial-utils.js</code>: Geographical and temporal proximity calculations</li><li><code>similarity-utils.js</code>: Text and entity matching algorithms</li><li><code>deduplication-utils.js</code>: Record scoring and merging logic</li></ul></li><li><strong>Integration with Reference Data</strong>: Uses cached incident type data for better matching</li></ol><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><ol><li><strong>Record Selection</strong>: Fetches recent raw_data records (last 30 days)</li><li><strong>Source Grouping</strong>: Groups records by source to ensure cross-source comparisons only</li><li><strong>Similarity Analysis</strong>: <ul><li>Calculates time proximity (hours between incidents)</li><li>Calculates spatial proximity (kilometers between coordinates)</li><li>Compares vessel details when available</li><li>Analyzes incident type similarities</li></ul></li><li><strong>Match Identification</strong>: Identifies potential matches above configurable threshold</li><li><strong>Primary Record Selection</strong>: Determines most complete/authoritative record</li><li><strong>Data Merging</strong>: Combines complementary information from matched records</li><li><strong>Record Updating</strong>: Updates Airtable records with merged data and relationship links</li><li><strong>Processing Trigger</strong>: Triggers the incident processing system after completion</li></ol><h2 id="similarity-scoring" tabindex="-1">Similarity Scoring <a class="header-anchor" href="#similarity-scoring" aria-label="Permalink to &quot;Similarity Scoring&quot;">​</a></h2><p>Similarity scores are calculated on a scale of 0.0 to 1.0, with higher scores indicating higher confidence in a match:</p><ul><li><strong>Time Proximity</strong>: 1.0 for same time, 0.0 for incidents ≥48 hours apart</li><li><strong>Spatial Proximity</strong>: 1.0 for same location, 0.0 for incidents ≥50km apart</li><li><strong>Vessel Similarity</strong>: Based on vessel name and IMO number matches</li><li><strong>Incident Type Similarity</strong>: Compares incident categorization</li></ul><p>The overall similarity formula prioritizes time and location while accommodating source-specific data patterns:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>totalScore = (timeScore * 0.4) + (spatialScore * 0.4) + (vesselScore * 0.1) + (incidentTypeScore * 0.1)</span></span></code></pre></div><p>Matches with a score ≥0.7 are considered candidates for merging.</p><h2 id="special-handling-for-missing-data" tabindex="-1">Special Handling for Missing Data <a class="header-anchor" href="#special-handling-for-missing-data" aria-label="Permalink to &quot;Special Handling for Missing Data&quot;">​</a></h2><p>The system is designed to handle source-specific data patterns:</p><ul><li>When both records lack vessel information (typical for ICC, MDAT, and UKMTO sources), a default vessel similarity score is assigned</li><li>Records with matching IMO numbers are given maximum vessel similarity regardless of other factors</li><li>Missing incident type data is handled gracefully with reference data lookups</li></ul><h2 id="data-fields" tabindex="-1">Data Fields <a class="header-anchor" href="#data-fields" aria-label="Permalink to &quot;Data Fields&quot;">​</a></h2><p>The deduplication system uses and updates the following fields in the raw_data table:</p><h3 id="tracking-fields" tabindex="-1">Tracking Fields <a class="header-anchor" href="#tracking-fields" aria-label="Permalink to &quot;Tracking Fields&quot;">​</a></h3><ul><li><strong>merge_status</strong>: Indicates merge status (&quot;merged&quot;, &quot;merged_into&quot;, or empty)</li><li><strong>merged_into</strong>: Links to primary record (for secondary records)</li><li><strong>related_raw_data</strong>: Links to secondary records (for primary records)</li><li><strong>merge_score</strong>: JSON metadata about the merge operation</li></ul><h3 id="standard-fields-used-for-matching" tabindex="-1">Standard Fields Used for Matching <a class="header-anchor" href="#standard-fields-used-for-matching" aria-label="Permalink to &quot;Standard Fields Used for Matching&quot;">​</a></h3><ul><li><strong>date</strong>: Incident date/time</li><li><strong>latitude/longitude</strong>: Geographical coordinates</li><li><strong>vessel_name</strong>: Vessel name (when available)</li><li><strong>vessel_imo</strong>: IMO number (when available)</li><li><strong>incident_type_name</strong>: Incident categorization</li><li><strong>source</strong>: Source system name</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>The deduplication system can be configured through environment variables and query parameters:</p><ul><li><strong>Scheduling</strong>: Set in <code>netlify.toml</code> (default: runs hourly)</li><li><strong>Confidence threshold</strong>: Default 0.7, configurable via queryString</li><li><strong>PUBLIC_URL</strong>: Required for triggering the processing function</li><li><strong>Record limit</strong>: Default 100, configurable via queryString</li></ul><h2 id="process-integration" tabindex="-1">Process Integration <a class="header-anchor" href="#process-integration" aria-label="Permalink to &quot;Process Integration&quot;">​</a></h2><p>The deduplication system runs before incident processing:</p><ol><li><code>deduplicate-cross-source-background.js</code> processes raw data to identify and merge duplicates</li><li>Upon completion, it triggers <code>process-raw-data-background.js</code> to create incident records</li><li>This sequence ensures duplicates are merged before incident creation</li></ol><h2 id="manual-operation" tabindex="-1">Manual Operation <a class="header-anchor" href="#manual-operation" aria-label="Permalink to &quot;Manual Operation&quot;">​</a></h2><p>For testing or manual operation, the function can be triggered with:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://your-netlify-site.netlify.app/.netlify/functions/deduplicate-cross-source-background&quot;</span></span></code></pre></div><p>With optional query parameters:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://your-netlify-site.netlify.app/.netlify/functions/deduplicate-cross-source-background?dryRun=true&amp;confidenceThreshold=0.75&quot;</span></span></code></pre></div>',38)]))}const p=i(r,[["render",o]]);export{h as __pageData,p as default};
